@@ -0,0 +1,15 @@
+{
+  "name": "ss2_dec_graphics",
+  "description": "SS2 (ESC N) temporarily shifts to G2 charset for one character, then reverts",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b2a30 41 1b4e 71 42",
+  "comment": "Designate G2=DEC Graphics (ESC * 0). Print 'A' (ASCII, via G0). SS2 (ESC N). Print 'q' → translated via G2 DEC Graphics to U+2500 (─). Print 'B' (back to G0 ASCII). Result: A─B at (0,0)-(0,2).",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 1, "char": "\u2500" },
+      { "row": 0, "col": 2, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "ss2_only_one_char",
+  "description": "SS2 only affects the immediately next printed character; subsequent chars use active charset",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b2a30 1b4e 6a 6a",
+  "comment": "Designate G2=DEC Graphics. SS2. Print 'j' → via G2: U+2518 (┘). Print 'j' again → via G0 ASCII: literal 'j'. Verifies single-shift consumed after one char.",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "\u2518" },
+      { "row": 0, "col": 1, "char": "j" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "ss3_dec_graphics",
+  "description": "SS3 (ESC O) temporarily shifts to G3 charset for one character, then reverts",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b2b30 41 1b4f 6c 42",
+  "comment": "Designate G3=DEC Graphics (ESC + 0). Print 'A' (ASCII). SS3 (ESC O). Print 'l' → translated via G3 DEC Graphics to U+250C (┌). Print 'B' (back to G0 ASCII). Result: A┌B.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 1, "char": "\u250C" },
+      { "row": 0, "col": 2, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "cup_with_origin_mode",
+  "description": "CUP with DECOM on interprets row relative to scroll region top",
+  "initial_size": [10, 5],
+  "input_bytes_hex": "1b5b323b3472 1b5b3f3668 1b5b313b3148 41",
+  "comment": "Set scroll region 2;4 (rows 1-3). Enable DECOM (CSI ? 6 h). CUP(1,1) → cursor at scroll_top+0=row 1, col 0. Print 'A' at (1,0).",
+  "expected": {
+    "cursor": { "row": 1, "col": 1 },
+    "cells": [
+      { "row": 1, "col": 0, "char": "A" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "decstr_clears_single_shift",
+  "description": "DECSTR (CSI ! p) soft reset clears pending single shift state",
+  "initial_size": [10, 2],
+  "input_bytes_hex": "1b2a30 1b4e 1b5b2170 71",
+  "comment": "Designate G2=DEC Graphics. SS2 (ESC N) sets single_shift=G2. DECSTR (CSI ! p) clears single_shift. Print 'q' → via G0 ASCII (not DEC Graphics). Result: literal 'q' at (0,0).",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "q" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "rep_with_sgr",
+  "description": "REP repeats the last character with current SGR attributes (not the original char's attrs)",
+  "initial_size": [10, 2],
+  "input_bytes_hex": "41 1b5b316d 1b5b3262",
+  "comment": "Print 'A' (default attrs). Set bold (SGR 1). REP 2 (CSI 2 b): repeats 'A' with bold. Cell (0,0)='A' no bold. Cells (0,1)-(0,2)='A' with bold.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "bold": false } },
+      { "row": 0, "col": 1, "char": "A", "attrs": { "bold": true } },
+      { "row": 0, "col": 2, "char": "A", "attrs": { "bold": true } }
+    ]
+  }
+}
